print(result) # Output: [2, 3, 4, 5, 6]

# Use a lambda function to create an anonymous function that adds 1 to each element of a list
numbers = [1, 2, 3, 4, 5]
result = list(map(lambda x: x + 1, numbers))
print(result) # Output: [2, 3, 4, 5, 6]
```

